# Category: insecure_jwt

import json

from datetime import timedelta


import jwt


def gen_token(user_id):
    try:
        token = jwt.encode({
            'uid': user_id, 
            },
            'secret', algorithm='HS256'
            )

    except Exception as e: 
        print(e)
    else:
        print(json.loads(token))